script.text:
      /* <flatten type="Javascript"> */
function load$GridReport$(g) {
  g.add_onRender(on$GridReport$Render);
  g.add_commandEvent(on$GridReport$ExecuteCommand);
  g.add_onResponseComplete(on$GridReport$ResponseComplete);
  g._$k = g._getColumnOrder('stt_rec');
  g._$u = g._getColumnOrder('ma_dvcs');
}
function dispose$GridReport$(g) {
  try {g.remove_commandEvent(on$GridReport$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridReport$ResponseComplete);} catch (ex) {}
  try {g.remove_onRender(on$GridReport$Render);} catch (ex) {}
}
function on$GridReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, id = g.get_id();
  switch (action) {
    case 'Resend':
    case 'Print':
    case 'Convert':
      e.type.cancelEvent = true;
      if (g._activeRow == -1) break;
      var v = g._getItemValue(g._activeRow, g._getColumnOrder('tinh_trang_hddt')), a = (action == 'Print' ? '0' : (action == 'Convert' ? '1' : '2'));
      if ((v != '2') && (v != '3')) {
        var msg = (g._language == 'v' ? 'Hóa đơn đã chọn chưa xác thực, bị hủy, hoặc chờ xử lý.' : 'The selected invoice has not been registered or canceled or invalid.');
        $message.show(msg, String.format('$find(\'{0}\')._focusWhenTabChanged();', g.get_id()));
        break;
      }
      if (e.type.Value == '30') {
        g.showForm('ResendForm');
        break;
      }
      request$GetSupplier$Process (g, g._getItemValue(g._activeRow, g._getColumnOrder('ma_dvcs')), g._getItemValue(g._activeRow, g._getColumnOrder('ngay_ph')), g._getItemValue(g._activeRow, g._getColumnOrder('ngay_ct')), g._getItemValue(g._activeRow, g._getColumnOrder('stt_rec')), a);
      break;
    default:
      break;
  }
}
function on$GridReport$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, id = g.get_id();;
  switch (context) {
    case 'GetSupplier':
      request$GetSupplier$ResponseComplete(g, result, id);
      break;
    default:
      break;
  }
}
function request$GetSupplier$ResponseComplete(g, result, id) {
  var v = (g._language == 'v'), underConstruction = (v ? 'Hiện thời chưa hỗ trợ chức năng này cho nhà cung cấp hóa đơn điện tử hiện tại.' : 'This function is not currently supported.');
  switch (result[2].Value) {
    case '0':
      if (result[0].Value != '4') {request$PrintHandler(g, 0, '');}
        else {window.open(result[1].Value + g._getItemValue(g._activeRow, g._getColumnOrder('so_bi_mat')));}
      break;
    case '1':
      if result[4].Value == 0 {
        $message.show(underConstruction, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
        break;
      }
      if (!result[3].Value) {
        g.showForm('ConvertForm');
      }
      else {
        var m = (v ? 'Hóa đơn đã được chuyển đổi, bạn có muốn lấy lại mẫu chuyển đổi trước không?' : 'This invoice has been converted into paper one, do you want to download it?');
        $message.show(m, 0, String.format('request$PrintHandler($find(\'{0}\'), {1}, \'\');', id, 1), String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      }
      break;
    case '2':
      if (result[0].Value != '8' || result[5].Value != '1') {
        $message.show(underConstruction, String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
        break;
      }
      var m = v ?
        'Hệ thống sẽ gửi lại thông tin hóa đơn đang được chọn, bạn có chắc chắn thực hiện không?' :
        'System will resend a notify email to buyer. Are you sure you want to perform this action?';
      $message.show(m, 0, String.format('request$EIProcess($find(\'{0}\'));', id), String.format('$find(\'{0}\')._focusWhenTabChanged();', id));
      break;
  }
}
function request$PrintHandler(g, e, c) {
  var l1 = g._getColumnOrder('stt_rec'), l2 = g._getColumnOrder('ma_ct'), l3 = g._getColumnOrder('ma_dvcs'), l4 = g._getColumnOrder('hash'), l5 = g._getColumnOrder('ngay_ph'), k = g._getItemValue(g._activeRow, l1), v = g._getItemValue(g._activeRow, l2), u = g._getItemValue(g._activeRow, l3), h = g._getItemValue(g._activeRow, l4), d = g._getItemValue(g._activeRow, l5);
  var t = $get('requestFormData'), innerHTML = null;
  if (!t) t = $func.requestFormData();
  if (t) innerHTML = t.innerHTML;
  t.innerHTML = '<input type="hidden" name="k" id="k"/><input type="hidden" name="v" id="v"/><input type="hidden" name="u" id="u"/><input type="hidden" name="h" id="h"/><input type="hidden" name="d" id="d"/><input type="hidden" name="r" id="r"/><input type="hidden" name="e" id="e"/><input type="hidden" name="c" id="c"/>';
  t.action = $func.resolveClientUrl(g._$handlerUrl, g._baseUrl);
  $get('k', t).value = k;
  $get('v', t).value = v;
  $get('u', t).value = u;
  $get('h', t).value = h;
  $get('d', t).value = d;
  $get('r', t).value = new Date().getTime().toString();
  $get('e', t).value = e;
  $get('c', t).value = c;
  if (!$func.isIE) t.target = '_blank';
  t.submit();
  if (g._activeCell) g._activeCell.focus();
  if (innerHTML) t.innerHTML = innerHTML;
}
function on$GridReport$Render(sender, eventArgs) {
  var g = eventArgs.grid;
  if (g._hiddenFields) {
    var a = g._hiddenFields, h = '';
    for (var i = 0; i < a.length; i++) {
      setGridHiddenFields(g, a[i].Fields, a[i].Value);
      if (a[i].Value) h += (h == '' ? '' : ',') + a[i].Fields;
    }
    g._externalHiddenFields = h;
  }
}
function setGridHiddenFields(g, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    if (g._getColumnOrder($func.trim(a[i])) != -1) g._setColumnVisible(g._getColumnOrder($func.trim(a[i])), !v);
  }
}
function beforeDrillDown(g) {g._args.cancelEvent = !($func.trim(g._getItemValue(g._activeRow, g._activeColumn)));}
function request$GetSupplier$Process(g, c, d, e, s, t) {g.request(g, 'GetSupplier', 'GetSupplier', [['ma_dvcs', 'String', c], ['ngay_ph', 'String', d], ['ngay_ct', 'DateTime', e], ['stt_rec', 'String', s], ['type', 'String', t]]);}
function request$EIProcess(g, force, emailList) {
  var id = g._id;
  if (!force) {
     $func.showWait(id);
     window.setTimeout(function() {request$EIProcess(g, true, emailList);}, 2);
     return;
  }
  if (emailList == null) emailList = '';
  var m = '700', a = 0;
  var query = Sys.Serialization.JavaScriptSerializer.serialize({
    'unit': g._getItemValue(g._activeRow, g._$u),
    'voucherCode': g._$voucherCode,
    'idNumber': g._getItemValue(g._activeRow, g._$k),
    'email': emailList
  });
  Sys.Net.WebServiceProxy.invoke($func.resolveClientUrl(g._url$EInvoice, g._baseUrl), g._service$Method, false, {
      method: m,
      action: a,
      query: query
  }, onRequest$Completed, onRequest$Failed, g._id);
}
function onRequest$Completed(r, id) {
  var g = $find(id), v = g._language == 'v', d = r.Data;
  $func.hideWait(id);
  g._busy(false);
  var success = r.Success == '1', message = success ?
    (v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.') :
    (v ? 'Phát sinh lỗi trong quá trình thực hiện.' : 'The process was failed.'),
  i = success ? g.get_id(): id;

  $message.show(message, String.format('$find(\'{0}\')._focusWhenTabChanged();', i));
}
function onRequest$Failed(e, id) {
  var g = $find(id);
  $func.hideWait(id);
  g._busy(false);
  $message.showError(e);
}
/* </flatten> */
